  1894→    public int deleteOldSegments() throws IOException {
  1895→        if (config().delete) {
  1896→            return deleteLogStartOffsetBreachedSegments() +
  1897→                    deleteRetentionSizeBreachedSegments() +
  1898→                    deleteRetentionMsBreachedSegments();
  1899→        } else {
  1900→            return deleteLogStartOffsetBreachedSegments();
