    17→package org.apache.kafka.tiered.storage.integration;
    18→
    19→import org.apache.kafka.tiered.storage.TieredStorageTestBuilder;
    20→import org.apache.kafka.tiered.storage.TieredStorageTestHarness;
    21→import org.apache.kafka.tiered.storage.specs.KeyValueSpec;
    22→
    23→import java.util.List;
    24→import java.util.Map;
    25→import java.util.concurrent.TimeUnit;
    26→
    27→import static org.apache.kafka.server.log.remote.storage.LocalTieredStorageEvent.EventType.DELETE_SEGMENT;
    28→
    29→public abstract class BaseDeleteSegmentsTest extends TieredStorageTestHarness {
    30→
    31→    @Override
    32→    public int brokerCount() {
    33→        return 1;
    34→    }
    35→
    36→    @Override
    37→    protected void writeTestSpecifications(TieredStorageTestBuilder builder) {
    38→        final Integer broker0 = 0;
    39→        final String topicA = "topicA";
    40→        final Integer p0 = 0;
    41→        final Integer partitionCount = 1;
    42→        final Integer replicationFactor = 1;
    43→        final Integer maxBatchCountPerSegment = 1;
    44→        final Map<Integer, List<Integer>> replicaAssignment = null;
    45→        final boolean enableRemoteLogStorage = true;
    46→        final int beginEpoch = 0;
    47→        final long startOffset = 3;
    48→
    49→        // Create topicA with 1 partition, 1 RF and enabled with remote storage.
    50→        builder.createTopic(topicA, partitionCount, replicationFactor, maxBatchCountPerSegment, replicaAssignment,
    51→                        enableRemoteLogStorage)
    52→                // produce events to partition 0 and expect 3 segments to be offloaded
    53→                .expectSegmentToBeOffloaded(broker0, topicA, p0, 0, new KeyValueSpec("k0", "v0"))
    54→                .expectSegmentToBeOffloaded(broker0, topicA, p0, 1, new KeyValueSpec("k1", "v1"))
    55→                .expectSegmentToBeOffloaded(broker0, topicA, p0, 2, new KeyValueSpec("k2", "v2"))
    56→                .expectEarliestLocalOffsetInLogDirectory(topicA, p0, 3L)
    57→                .produceWithTimestamp(topicA, p0, new KeyValueSpec("k0", "v0"), new KeyValueSpec("k1", "v1"),
    58→                        // DeleteSegmentsByRetentionTimeTest uses a tiny retention time, which could cause the active 
